select (select (cast('100.00' as decimal(5,2)) * v_1) / v_2 from (select sum(case when v_3 like 'PROMO%' then v_4 * (1 - v_5) else cast(0 as decimal(12,2)) end) as v_1, sum(v_4 * (1 - v_5)) as v_2 from (select * from (select * from (select "l_orderkey" as v_6, "l_partkey" as v_7, "l_suppkey" as v_8, "l_linenumber" as v_9, "l_quantity" as v_10, "l_extendedprice" as v_4, "l_discount" as v_5, "l_tax" as v_11, "l_returnflag" as v_12, "l_linestatus" as v_13, "l_shipdate" as v_14, "l_commitdate" as v_15, "l_receiptdate" as v_16, "l_shipinstruct" as v_17, "l_shipmode" as v_18, "l_comment" as v_19 from "lineitem") s where (v_14 >= (date('1995-09-01', '+0 seconds'))) and (v_14 < (date('1995-09-01', '+1 month')))) l inner join (select "p_partkey" as v_20, "p_name" as v_21, "p_mfgr" as v_22, "p_brand" as v_23, "p_type" as v_3, "p_size" as v_24, "p_container" as v_25, "p_retailprice" as v_26, "p_comment" as v_27 from "part") r on v_7 = v_20) s) s)
